import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Краш-репорты","description":"Узнайте, что делать с краш-репортами и как их читать.","frontmatter":{"title":"Краш-репорты","description":"Узнайте, что делать с краш-репортами и как их читать.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"ru_ru/1.20.4/players/troubleshooting/crash-reports.md","filePath":"versions/1.20.4/translated/ru_ru/players/troubleshooting/crash-reports.md","lastUpdated":1766341111000}`);var a={name:`ru_ru/1.20.4/players/troubleshooting/crash-reports.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Краш-репорты <a class="header-anchor" href="#h1" aria-label="Permalink to “Краш-репорты”">​</a></h1><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Если у вас возникли какие-либо трудности с поиском причины краша, вы можете обратиться за помощью в <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">дискорд Fabric</a> в каналах <code>#player-support</code> или <code>#server-admin-support</code>.</p></div><p>Краш-репорты являются очень важной частью устранения проблем с вашей игрой или сервером. Они содержат много информации о краше и могут помочь вам найти причину краша.</p><h2 id="поиск-краш-репортов" tabindex="-1">Поиск краш-репортов <a class="header-anchor" href="#поиск-краш-репортов" aria-label="Permalink to “Поиск краш-репортов”">​</a></h2><p>Краш-репорты находятся в папке <code>crash-reports</code> в папке вашей игры. Если у вас сервер, то они хранятся в папке <code>crash-reports</code> в папке сервера.</p><p>Для сторонних лаунчеров вам следует посмотреть в их документацию, чтобы найти краш-репорты.</p><p>Краш-репорты можно найти по этим путям:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-23" id="tab-24" checked><label data-title="Windows" for="tab-24">Windows</label><input type="radio" name="group-23" id="tab-25"><label data-title="macOS" for="tab-25">macOS</label><input type="radio" name="group-23" id="tab-26"><label data-title="Linux" for="tab-26">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\crash-reports</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/crash-reports</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/crash-reports</span></span></code></pre></div></div></div><h2 id="чтение-краш-репортов" tabindex="-1">Чтение краш-репортов <a class="header-anchor" href="#чтение-краш-репортов" aria-label="Permalink to “Чтение краш-репортов”">​</a></h2><p>Краш-репорты очень большие, их чтение может быть непонятным. Однако они содержат много информации о краше и могут помочь вам найти причину краша.</p><p>Для этого гайда, мы используем <a href="https://github.com/FabricMC/fabric-docs/blob/main/public/assets/players/crash-report-example.log" target="_blank" rel="noreferrer">этот краш-репорт в качестве примера</a>.</p><h3 id="разделы-краш-репорта" tabindex="-1">Разделы краш-репорта <a class="header-anchor" href="#разделы-краш-репорта" aria-label="Permalink to “Разделы краш-репорта”">​</a></h3><p>Краш-репорты состоят из нескольких разделов, разделённых заголовками:</p><ul><li><code>---- Minecraft Crash Report ----</code>, краткое описание краша. Этот раздел содержит основную ошибку, вызвавшую краш, время возникновения и трассировку стека. Это главный раздел краш-репорта, так как трассировка стека обычно содержит мод, который вызывает краш.</li><li><code>-- Last Reload --</code>, этот раздел на самом деле бесполезен, если только краш не произошёл во время перезагрузки ресурсов (<kbd>F3</kbd>+<kbd>T</kbd>). Этот раздел содержит время последней перезагрузки и трассировки стеков любых ошибок, возникших в процессе перезагрузки. Эти ошибки обычно происходят из-за ресурс-паков, и их можно игнорировать, если только они не вызывают проблем с игрой.</li><li><code>-- System Details --</code>, этот раздел содержит информацию о вашем компьютере, такую как операционная система, версия Java и объем памяти, выделенный для игры. Этот раздел полезен для определения того, используете ли вы правильную версию Java и выделили ли вы игре достаточно памяти. <ul><li>В этом разделе Fabric добавит строку <code>Fabric Mods:</code> со списком всех установленных модов. Этот раздел полезен для определения конфликтов между модами.</li></ul></li></ul><h3 id="разбор-краш-репорта" tabindex="-1">Разбор краш-репорта <a class="header-anchor" href="#разбор-краш-репорта" aria-label="Permalink to “Разбор краш-репорта”">​</a></h3><p>Теперь, когда мы знаем, что представляет собой каждый раздел, мы можем начать разбирать краш-репорт и находить причину краша.</p><p>Используя файл выше, мы можем проанализировать краш-репорт и найти причину краша, включая моды, которые вызвали сбой.</p><p>Трассировка стека в разделе <code>---- Minecraft Crash Report ----</code> является наиболее важной в данном случае, поскольку она содержит основную ошибку, вызвавшую краш. В нашем случае ошибка - <code>java.lang.NullPointerException: Cannot invoke &quot;net.minecraft.class_2248.method_9539()&quot; because &quot;net.minecraft.class_2248.field_10540&quot; is null</code>.</p><p>Учитывая количество модов, упомянутых в стеке, может быть трудно указать на конкретную причину, но первое, что нужно сделать, это найти мод, который вызвал сбой.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>at snownee.snow.block.ShapeCaches.get(ShapeCaches.java:51)</span></span>
<span class="line"><span>at snownee.snow.block.SnowWallBlock.method_9549(SnowWallBlock.java:26) // [!code focus]</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>at me.jellysquid.mods.sodium.client.render.chunk.compile.pipeline.BlockOcclusionCache.shouldDrawSide(BlockOcclusionCache.java:52)</span></span>
<span class="line"><span>at link.infra.indium.renderer.render.TerrainBlockRenderInfo.shouldDrawFaceInner(TerrainBlockRenderInfo.java:31)</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>В данном случае мод, вызвавший сбой, называется <code>snownee</code>, поскольку это первый мод, упомянутый в трассировке стека.</p><p>Однако, учитывая количество упомянутых модов, это может означать, что между модами проблемы с совместимостью, и мод, вызвавший краш, может быть не тем модом, который виноват. В этом случае лучше всего сообщить о краше автору мода и позволить ему изучить краш.</p><h2 id="краш-миксина" tabindex="-1">Краш миксина <a class="header-anchor" href="#краш-миксина" aria-label="Permalink to “Краш миксина”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Миксины - это способ для модов модифицировать игру без необходимости изменять исходный код игры. Они используются многими модами и являются очень мощным инструментом для разработчиков модов.</p></div><p>Когда происходит краш миксина, в трассировке стека обычно упоминается миксин и класс, который он модифицирует.</p><p>Метод миксина будет содержать <code>mod-id$handlerName</code> в трассировке стека, где <code>mod-id</code> - айди мода, а <code>handlerName</code> - название обработчика миксина.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>... net.minecraft.class_2248.method_3821$$$mod-id$handlerName() ... // [!code focus]</span></span></code></pre></div><p>Вы можете использовать эту информацию, чтобы найти мод, вызвавший краш, и сообщить о нём автору мода.</p><h2 id="что-делать-с-краш-репортами" tabindex="-1">Что делать с краш-репортами <a class="header-anchor" href="#что-делать-с-краш-репортами" aria-label="Permalink to “Что делать с краш-репортами”">​</a></h2><p>Лучшее, что можно сделать с краш-репортами - это загрузить их на сайт для текстов, а затем отправить ссылку автору мода либо в раздел с проблемами мода, либо через какую-либо форму связи (дискорд и т.д.).</p><p>Это позволит автору мода изучить краш, потенциально воспроизвести его и решить проблему, которая его вызвала.</p><p>Распространенными сайтами для текстов, которые часто используются для краш-репортов, являются:</p><ul><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,33)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};